import { API_URL } from '../../config.js';
import {
    ESTIMATE_SUBMIT_SYNC_TAG,
    getPendingEstimateSubmits,
    markEstimateSubmitted,
    setEstimateSubmitImagePath,
    type EstimateSubmitEntry,
} from './estimate-submit-store.js';

/**
 * Drains the async-estimate submit queue. Story 221.
 *
 * For each pending submit: upload its image if it still carries bytes (persist
 * the returned path first, so a re-drain never re-uploads and orphans a photo),
 * then POST the async job with the `client_submit_id` — idempotent server-side
 * (migration 029), so a re-drain after the app was killed mid-POST yields one
 * job. On success mark it submitted and broadcast so an open review screen swaps
 * from "queued" to polling the real server job.
 *
 * Own fetch calls (no service-layer imports) so it stays reachable from the SW
 * `sync` handler without dragging the whole app in — mirrors
 * image-upload-shipping.ts. On error the entry is left in place and the first
 * error re-thrown, so `event.waitUntil` reports failure and the browser
 * re-fires `sync` when connectivity returns.
 */

export const ESTIMATE_SUBMIT_SUCCESS_CHANNEL = 'motivation-estimate-submits';

export interface EstimateSubmitSuccessMessage {
    type: 'estimate-submit-success';
    client_submit_id: string;
    server_job_id: string;
}

export interface EstimateShippingDeps {
    fetch?: typeof fetch;
    apiUrl?: string;
    now?: () => string;
    broadcast?: (message: EstimateSubmitSuccessMessage) => void;
}

export interface EstimateShippingResult {
    submitted: number;
    failed: number;
}

// Single-flight within this realm: the review screen re-nudges the drain every
// poll (2.5s), which on a slow link (the story's own restaurant scenario) can
// outlast an in-progress image upload. Coalescing concurrent calls avoids
// uploading the same photo twice; the server's client_submit_id dedup is the
// backstop, this just spares the wasted upload.
let inFlight: Promise<EstimateShippingResult> | null = null;

export function shipPendingEstimateSubmits(deps: EstimateShippingDeps = {}): Promise<EstimateShippingResult> {
    if (inFlight) return inFlight;
    inFlight = drainOnce(deps).finally(() => { inFlight = null; });
    return inFlight;
}

async function drainOnce(deps: EstimateShippingDeps): Promise<EstimateShippingResult> {
    const fetchImpl = deps.fetch ?? fetch.bind(globalThis);
    const apiBase = deps.apiUrl ?? API_URL;
    const now = deps.now ?? (() => Temporal.Now.instant().toString());
    const broadcast = deps.broadcast ?? defaultBroadcast;

    let submitted = 0;
    let failed = 0;
    const errors: Error[] = [];

    while (true) {
        const batch = await getPendingEstimateSubmits(25);
        if (batch.length === 0) break;

        for (const entry of batch) {
            try {
                let imagePath = entry.image_path;
                if (!imagePath && entry.image) {
                    imagePath = await uploadImage(entry.image.blob, entry.image.filename, fetchImpl, apiBase);
                    // Persist before the estimate POST: a crash here must not
                    // re-upload the bytes on the next drain.
                    await setEstimateSubmitImagePath(entry.id, imagePath);
                }
                const serverJobId = await submitJob(entry, imagePath, fetchImpl, apiBase);
                await markEstimateSubmitted(entry.id, serverJobId, now());
                broadcast({ type: 'estimate-submit-success', client_submit_id: entry.id, server_job_id: serverJobId });
                submitted += 1;
            } catch (err) {
                failed += 1;
                errors.push(err instanceof Error ? err : new Error(String(err)));
                // Leave the entry in place; stop this fire so a persistent
                // failure (offline) doesn't spin the whole batch.
                break;
            }
        }

        if (failed > 0) break;
    }

    if (errors.length > 0) throw errors[0];
    return { submitted, failed };
}

async function uploadImage(blob: Blob, filename: string, fetchImpl: typeof fetch, apiBase: string): Promise<string> {
    const form = new FormData();
    form.set('image', blob, filename || 'meal.jpg');
    const response = await fetchImpl(`${apiBase}/api/files/images?scope=ai`, { method: 'POST', body: form });
    if (!response.ok) {
        const text = await response.text().catch(() => '');
        throw new Error(`Image upload failed (${response.status}): ${text}`);
    }
    const body = await response.json() as { image_path?: string };
    if (!body.image_path) throw new Error('Image upload response did not include image_path');
    return body.image_path;
}

async function submitJob(entry: EstimateSubmitEntry, imagePath: string, fetchImpl: typeof fetch, apiBase: string): Promise<string> {
    const response = await fetchImpl(`${apiBase}/api/sections/health/food-items/estimate/async`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
            description: entry.description || undefined,
            image_path: imagePath || undefined,
            date: entry.date,
            meal_type: entry.meal_type,
            client_submit_id: entry.id,
        }),
    });
    if (!response.ok) {
        const text = await response.text().catch(() => '');
        throw new Error(`Estimate submit failed (${response.status}): ${text}`);
    }
    const body = await response.json() as { id?: string };
    if (!body.id) throw new Error('Estimate submit response did not include a job id');
    return body.id;
}

function defaultBroadcast(message: EstimateSubmitSuccessMessage): void {
    if (typeof BroadcastChannel === 'undefined') return;
    const ch = new BroadcastChannel(ESTIMATE_SUBMIT_SUCCESS_CHANNEL);
    try {
        ch.postMessage(message);
    } finally {
        ch.close();
    }
}

/**
 * Register the Background Sync tag so a submit made offline ships when
 * connectivity returns even if the app is closed. Throws when Background Sync
 * is unavailable (Chrome-only app with secure-origin flags) — fail loud.
 */
export async function requestEstimateSubmitSync(): Promise<void> {
    if (typeof navigator === 'undefined' || !navigator.serviceWorker) {
        throw new Error('Service Worker is not available — estimate submits cannot ship');
    }
    const registration = await navigator.serviceWorker.ready;
    if (!registration.sync) {
        throw new Error('Background Sync API is not available — estimate submits cannot ship');
    }
    await registration.sync.register(ESTIMATE_SUBMIT_SYNC_TAG);
}
